using System.Collections.Generic;
using Unity.Burst;
using Unity.Collections;
using Unity.Jobs;
using Unity.Mathematics;
using UnityEngine;

[BurstCompile]

public struct PoissonDiscJob : IJob
{

    public int width;
    public int height;
    public float minRadius;
    public float maxRadius;
    public int k;
    public NativeArray<int2> pointsOut;
    public int chunkSize;
    public float2 position;


    public void Execute()
    {
        NativeArray<int2> spawnPoints = new NativeArray<int2>(width * height, Allocator.TempJob);
        NativeArray<int2> points = new NativeArray<int2>(width * height, Allocator.TempJob);
        Unity.Mathematics.Random random = new Unity.Mathematics.Random(1234);

        spawnPoints[0] = new int2(width / 2, height / 2);
        int spawnCount = 1;
        int pointCount = 0;

        // Use spawnCount as the active length. Previously checking spawnPoints.Length
        // caused an infinite loop because Length is the fixed capacity.
        while (spawnCount > 0)
        {
            int spawnIndex = random.NextInt(0, spawnCount);
            int2 spawnCenter = spawnPoints[spawnIndex];
            bool candidateAccepted = false;
            float noiseValue = noise.snoise(new float2(spawnCenter.x + position.x * chunkSize, spawnCenter.y + position.y * chunkSize) * 0.1f);

            for (int i = 0; i < k; i++)
            {
                float angle = random.NextFloat(0, Mathf.PI * 2);
                float noiseRadius = minRadius + noiseValue * (maxRadius - minRadius);
                float distance = random.NextFloat(noiseRadius, 2 * noiseRadius);
                int2 candidate = spawnCenter + new int2(Mathf.RoundToInt(Mathf.Cos(angle) * distance), Mathf.RoundToInt(Mathf.Sin(angle) * distance));

                if (candidate.x >= 0 && candidate.x < width && candidate.y >= 0 && candidate.y < height)
                {
                    bool valid = true;
                    for (int p = 0; p < pointCount; p++)
                    {
                        var point = points[p];
                        int dx = point.x - candidate.x;
                        int dy = point.y - candidate.y;
                        if (dx * dx + dy * dy < (int)(noiseRadius * noiseRadius))
                        {
                            valid = false;
                            break;
                        }
                    }

                    if (valid)
                    {
                        // add to points
                        points[pointCount] = candidate;
                        pointCount++;

                        // add to spawn list if there's capacity
                        if (spawnCount < spawnPoints.Length)
                        {
                            spawnPoints[spawnCount] = candidate;
                            spawnCount++;
                        }

                        candidateAccepted = true;
                        break;
                    }
                }
            }

            if (!candidateAccepted)
            {
                // remove this spawn by swapping with the last active one
                spawnCount--;
                if (spawnIndex < spawnCount)
                {
                    spawnPoints[spawnIndex] = spawnPoints[spawnCount];
                }
            }
        }

        for (int i = 0; i < pointsOut.Length; i++)
        {
            if (i < pointCount)
            {
                pointsOut[i] = points[i];
            }
            else
            {
                pointsOut[i] = new int2(0, 0); // No more points to generate
            }
        }

        // dispose temporaries
        spawnPoints.Dispose();
        points.Dispose();
    }
}

